func (c *AssemblyCache) Set(key, result string) {
	c.mu.Lock()
	defer c.mu.Unlock()

	c.entries[key] = assemblyCacheEntry{...}

	if len(c.entries) > maxAssemblyCacheSize {
		// First pass: evict expired entries
		now := time.Now()
		for k, e := range c.entries {
			if now.After(e.expiresAt) {
				delete(c.entries, k)
			}
		}
		// Second pass: if still over limit, evict the oldest entry
		for len(c.entries) > maxAssemblyCacheSize {
			var oldestKey string
			var oldestTime time.Time
			for k, e := range c.entries {
				if oldestKey == "" || e.expiresAt.Before(oldestTime) {
					oldestKey = k
					oldestTime = e.expiresAt
				}
			}
			if oldestKey != "" {
				delete(c.entries, oldestKey)
			}
		}
	}
}
```

**Eviction strategy:** First evict expired entries, then evict oldest (by expiration time).

**TOCTOU race - Lines 106-124:**
```go
func (c *AssemblyCache) Get(key string) (string, bool) {
	c.mu.RLock()
	entry, ok := c.entries[key]
	c.mu.RUnlock()  // Line 109 - lock released
	if !ok {
		return "", false
	}
	if time.Now().After(entry.expiresAt) {
		// Upgrade to write lock and remove the expired entry
		c.mu.Lock()  // Line 115 - lock re-acquired
		// Re-check under write lock (another goroutine may have updated it)
		if e, exists := c.entries[key]; exists && time.Now().After(e.expiresAt) {
			delete(c.entries, key)
		}
		c.mu.Unlock()
		return "", false
	}
	return entry.result, true
}
```

**TOCTOU prevention:** YES - The code explicitly handles it by re-checking under write lock (line 117: re-checks existence and expiration).

